const body = $json.body || $json;
const source = body.source || 'operator';

const SITE_MAP = {
  sinabarimd: { domain: 'sinabarimd.com', requires_hub_link: false },
  sinabari_net: { domain: 'sinabari.net', requires_hub_link: true },
  sinabariplasticsurgery: { domain: 'sinabariplasticsurgery.com', requires_hub_link: true },
};

let urls_to_check = [];

if (body.article_url) {
  urls_to_check.push({
    site_id: body.site_id,
    article_url: body.article_url,
    domain: SITE_MAP[body.site_id]?.domain || body.site_id,
    requires_hub_link: SITE_MAP[body.site_id]?.requires_hub_link ?? true,
  });
} else if (body.article_urls && Array.isArray(body.article_urls)) {
  for (const entry of body.article_urls) {
    const sid = entry.site_id || body.site_id;
    urls_to_check.push({
      site_id: sid,
      article_url: entry.article_url || entry.url,
      domain: SITE_MAP[sid]?.domain,
      requires_hub_link: SITE_MAP[sid]?.requires_hub_link ?? true,
    });
  }
} else {
  // Sweep mode
  const staticData = $getWorkflowStaticData('global');
  const registry = staticData.url_registry || {};
  for (const [site_id, articles] of Object.entries(registry)) {
    for (const article of articles) {
      urls_to_check.push({
        site_id,
        article_url: article.url,
        domain: SITE_MAP[site_id]?.domain,
        requires_hub_link: SITE_MAP[site_id]?.requires_hub_link ?? true,
      });
    }
  }
}

if (urls_to_check.length === 0) {
  return [{ json: { error: true, message: 'No URLs to check.' } }];
}

return urls_to_check.map(u => ({ json: { ...u, source, checked_at: new Date().toISOString() } }));

const upstream = $('Resolve URLs').first().json;
const site_id = upstream.site_id;
const article_url = upstream.article_url;
const domain = upstream.domain;
const requires_hub_link = upstream.requires_hub_link;
const checked_at = upstream.checked_at;
const source = upstream.source;

const html = typeof $json.data === 'string' ? $json.data : (typeof $json === 'string' ? $json : '');
const http_ok = html.length > 100;

const checks = [];
const AUTHOR_NAME = 'Dr. Sina Bari, MD';
const AUTHOR_ID = 'https://sinabarimd.com/#sinabari';

const chk = (id, label, passed, detail, severity = 'error') => {
  checks.push({ id, label, passed, detail, severity });
};

// 1. Page loads
chk('http_200', 'Page loads successfully', http_ok, http_ok ? 'OK' : 'Failed to fetch page content');

if (!http_ok) {
  return [{ json: { site_id, article_url, domain, checked_at, source, score: 0, grade: 'F', passed: false, total_checks: 1, checks, failed_checks: checks.filter(c => !c.passed), warnings: [] } }];
}

// 2. Title
const titleM = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleM?.[1]?.trim() || '';
chk('title', 'Title tag exists', title.length > 0, title.length ? '"' + title.slice(0,70) + '"' : 'Missing');

// 3. Meta description
const descM = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']*)["']/i) || html.match(/<meta\s+content=["']([^"']*)["']\s+name=["']description["']/i);
chk('meta_desc', 'Meta description exists', !!descM, descM ? descM[1].length + ' chars' : 'Missing');

// 4. Canonical
const canonM = html.match(/<link\s+rel=["']canonical["']\s+href=["']([^"']*)["']/i) || html.match(/<link\s+href=["']([^"']*)["']\s+rel=["']canonical["']/i);
const canon = canonM?.[1] || '';
chk('canonical', 'Canonical URL matches page', canon === article_url || canon === article_url.replace(/\/$/, ''), canon ? 'canonical=' + canon : 'Missing');

// 5. og:type
const ogtM = html.match(/<meta\s+property=["']og:type["']\s+content=["']([^"']*)["']/i) || html.match(/<meta\s+content=["']([^"']*)["']\s+property=["']og:type["']/i);
chk('og_type', 'og:type is article', ogtM?.[1]?.toLowerCase() === 'article', ogtM ? ogtM[1] : 'Missing');

// 6. og:site_name
const ogsM = html.match(/<meta\s+property=["']og:site_name["']\s+content=["']([^"']*)["']/i) || html.match(/<meta\s+content=["']([^"']*)["']\s+property=["']og:site_name["']/i);
chk('og_site_name', 'og:site_name exists', !!ogsM, ogsM ? ogsM[1] : 'Missing');

// 7. article:published_time
const aptM = html.match(/article:published_time["']\s+content=["']([^"']*)["']/i) || html.match(/content=["']([^"']*)["']\s+property=["']article:published_time["']/i);
chk('pub_time', 'article:published_time exists', !!aptM, aptM ? aptM[1] : 'Missing');

// 8. twitter:card
const twM = html.match(/twitter:card["']\s+content=["']([^"']*)["']/i) || html.match(/content=["']([^"']*)["']\s+name=["']twitter:card["']/i);
chk('twitter', 'twitter:card exists', !!twM, twM ? twM[1] : 'Missing');

// 9. meta author
const authM = html.match(/<meta\s+name=["']author["']\s+content=["']([^"']*)["']/i) || html.match(/<meta\s+content=["']([^"']*)["']\s+name=["']author["']/i);
chk('meta_author', 'Meta author is Dr. Sina Bari, MD', authM?.[1] === AUTHOR_NAME, authM ? authM[1] : 'Missing');

// 10-11. Schema checks
const ldBlocks = html.match(/<script[^>]+application\/ld\+json[^>]*>([\s\S]*?)<\/script>/gi) || [];
let hasArticleType = false, hasAuthorId = false, hasFaq = false, schemaType = '';
for (const block of ldBlocks) {
  try {
    const inner = block.match(/>([\s\S]*?)<\/script>/i)?.[1] || '{}';
    const parsed = JSON.parse(inner);
    const items = parsed['@graph'] ? parsed['@graph'] : [parsed];
    for (const item of items) {
      const t = item['@type'];
      if (t === 'Article' || t === 'MedicalWebPage') { hasArticleType = true; schemaType = t; }
      if (t === 'FAQPage') hasFaq = true;
      if (item.author?.['@id'] === AUTHOR_ID) hasAuthorId = true;
    }
  } catch (_) {}
}
chk('schema_type', 'Schema Article/MedicalWebPage exists', hasArticleType, hasArticleType ? schemaType : 'Missing');
chk('schema_author_id', 'Schema author @id = sinabarimd.com/#sinabari', hasAuthorId, hasAuthorId ? 'OK' : 'Missing @id');

// 12. FAQPage (warning)
chk('faq_schema', 'FAQPage schema exists', hasFaq, hasFaq ? 'OK' : 'No FAQPage — AEO opportunity missed', 'warning');

// 13. Author byline
const hasByline = html.includes('<aside') && html.split('<aside')[1]?.includes('sinabarimd.com/about');
chk('author_byline', 'Author byline with sinabarimd.com/about link', hasByline, hasByline ? 'OK' : 'Missing byline block');

// 14. Hub backlink (satellite sites only)
if (requires_hub_link) {
  const hasHub = /href=["']https?:\/\/(www\.)?sinabarimd\.com/i.test(html);
  chk('hub_backlink', 'Link to sinabarimd.com exists', hasHub, hasHub ? 'OK' : 'No sinabarimd.com link');
}

// 15. Articles nav link (warning)
chk('articles_nav', 'Nav has /articles/ link', html.includes('/articles/'), html.includes('/articles/') ? 'OK' : 'Missing', 'warning');


// 16. Outbound source links (warning)
const extLinkRe = /href=["']https?:\/\/(?!sinabarimd\.com|sinabari\.net|sinabariplasticsurgery\.com|drsinabari\.com)[^"']+["']/gi;
const extLinks = (html || '').match(extLinkRe) || [];
chk('outbound_links', 'Has outbound authority links', extLinks.length > 0, extLinks.length ? extLinks.length + ' external links' : 'No outbound links — add 2-3 for E-E-A-T', 'warning');

// Score (errors only, warnings excluded)
const errors = checks.filter(c => c.severity === 'error');
const passedErrors = errors.filter(c => c.passed).length;
const score = errors.length > 0 ? Math.round((passedErrors / errors.length) * 100) : 100;
const grade = score >= 95 ? 'A+' : score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 65 ? 'C' : score >= 50 ? 'D' : 'F';

return [{ json: {
  site_id, article_url, domain, checked_at, source, score, grade,
  passed: score >= 80,
  total_checks: checks.length,
  failed_checks: errors.filter(c => !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  warnings: checks.filter(c => c.severity === 'warning' && !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  checks,
} }];

const result = $json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.qa_results) staticData.qa_results = {};
if (!staticData.qa_history) staticData.qa_history = [];
if (!staticData.url_registry) staticData.url_registry = {};

// Guard: don't store homepage URLs as article results
const url = result.article_url || '';
if (url.endsWith('/') || !url.includes('/articles/')) {
  // This is a homepage or non-article URL — skip article storage
  return [{ json: { ...result, skipped: true, reason: 'Not an article URL — use domain QA for homepages' } }];
}

staticData.qa_results[result.article_url] = {
  site_id: result.site_id,
  score: result.score,
  grade: result.grade,
  passed: result.passed,
  checked_at: result.checked_at,
  failed_checks: result.failed_checks,
  warnings: result.warnings,
};

staticData.qa_history.push({
  article_url: result.article_url,
  site_id: result.site_id,
  score: result.score,
  grade: result.grade,
  checked_at: result.checked_at,
});
if (staticData.qa_history.length > 100) staticData.qa_history = staticData.qa_history.slice(-100);

if (!staticData.url_registry[result.site_id]) staticData.url_registry[result.site_id] = [];
const existing = staticData.url_registry[result.site_id];
if (!existing.find(u => u.url === result.article_url)) {
  existing.push({ url: result.article_url, first_checked: result.checked_at });
}

return [{ json: result }];

const staticData = $getWorkflowStaticData('global');
const qa_results = staticData.qa_results || {};
const qa_history = staticData.qa_history || [];
const domain_results = staticData.domain_results || {};
const portfolio_result = staticData.portfolio_result || null;
const suppressed = staticData.suppressed_checks || {};

const sites = {};
for (const [url, result] of Object.entries(qa_results)) {
  if (!sites[result.site_id]) sites[result.site_id] = { articles: [], avg_score: 0 };
  sites[result.site_id].articles.push({ url, ...result });
}
for (const site of Object.values(sites)) {
  site.avg_score = Math.round(site.articles.reduce((s, a) => s + a.score, 0) / site.articles.length);
}

return [{ json: {
  article_results_by_site: sites,
  domain_results,
  portfolio_result,
  suppressed_checks: suppressed,
  total_articles_checked: Object.keys(qa_results).length,
  recent_history: qa_history.slice(-20),
} }];

const body = $json.body || $json;
const SITES = {
  sinabarimd: { domain: 'sinabarimd.com', role: 'canonical_hub', expected_schema: ['Person', 'ProfilePage'], requires_geo: true, requires_sameas: true },
  sinabari_net: { domain: 'sinabari.net', role: 'satellite', expected_schema: ['WebSite', 'WebPage'], requires_geo: false, requires_sameas: false },
  sinabariplasticsurgery: { domain: 'sinabariplasticsurgery.com', role: 'satellite', expected_schema: ['WebSite', 'MedicalWebPage'], requires_geo: false, requires_sameas: false },
  drsinabari: { domain: 'drsinabari.com', role: 'satellite', expected_schema: ['WebSite', 'WebPage'], requires_geo: false, requires_sameas: false },
};

let sites_to_check = [];
if (body.site_id && SITES[body.site_id]) {
  sites_to_check.push({ site_id: body.site_id, ...SITES[body.site_id] });
} else {
  sites_to_check = Object.entries(SITES).map(([id, s]) => ({ site_id: id, ...s }));
}

return sites_to_check.map(s => ({ json: { ...s, checked_at: new Date().toISOString(), source: body.source || 'operator' } }));

const upstream = $('Resolve Domains').first().json;
const site_id = upstream.site_id;
const domain = upstream.domain;
const role = upstream.role;
const expected_schema = upstream.expected_schema;
const requires_geo = upstream.requires_geo;
const requires_sameas = upstream.requires_sameas;
const checked_at = upstream.checked_at;

const html = typeof $json.data === 'string' ? $json.data : (typeof $json === 'string' ? $json : JSON.stringify($json));
const http_ok = html.length > 500;

const checks = [];
const chk = (id, label, passed, detail, severity = 'error') => {
  checks.push({ id, label, passed, detail, severity });
};

chk('http_200', 'Homepage loads', http_ok, http_ok ? 'OK' : 'Failed (' + html.length + ' bytes)');
if (!http_ok) {
  return [{ json: { qa_type: 'domain', site_id, domain, checked_at, score: 0, grade: 'F', passed: false, checks, failed_checks: checks, warnings: [] } }];
}

const titleM = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
chk('title', 'Title tag exists', !!(titleM && titleM[1] && titleM[1].trim()), titleM ? '"' + titleM[1].trim().slice(0, 70) + '"' : 'Missing');

const descM = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']*)["']/i);
chk('meta_desc', 'Meta description exists', !!descM, descM ? descM[1].length + ' chars' : 'Missing');

const canonM = html.match(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']*)["']/i);
chk('canonical', 'Canonical URL present', !!canonM, canonM ? canonM[1] : 'Missing');

const ogtM = html.match(/og:type["']\s+content=["']([^"']*)["']/i);
chk('og_type', 'og:type present', !!ogtM, ogtM ? ogtM[1] : 'Missing', 'warning');

// Schema parsing - extract JSON-LD blocks
const ldRegex = /type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/gi;
let foundTypes = [];
let hasAuthorId = false;
let sameAsCount = 0;
let personCount = 0;
let match;
while ((match = ldRegex.exec(html)) !== null) {
  try {
    const parsed = JSON.parse(match[1]);
    const items = parsed['@graph'] ? parsed['@graph'] : [parsed];
    for (const item of items) {
      if (item['@type']) { const t = Array.isArray(item['@type']) ? item['@type'] : [item['@type']]; foundTypes.push(...t); }
      if (item['@type'] === 'Person') personCount++;
      if (item['@id'] === 'https://sinabarimd.com/#sinabari') hasAuthorId = true;
      if (item.author && item.author['@id'] === 'https://sinabarimd.com/#sinabari') hasAuthorId = true;
      if (item.sameAs && Array.isArray(item.sameAs)) sameAsCount = item.sameAs.length;
    }
  } catch (_) {}
}

const hasExpected = expected_schema.every(t => foundTypes.includes(t));
chk('schema_types', 'Schema has ' + expected_schema.join(' + '), hasExpected, 'Found: [' + foundTypes.join(', ') + ']');
chk('schema_entity', 'References sinabarimd.com/#sinabari', hasAuthorId, hasAuthorId ? 'OK' : 'Missing');

if (role === 'satellite') {
  chk('no_person', 'No Person schema on satellite', personCount === 0, personCount ? personCount + ' Person found' : 'OK');
  chk('no_sameas', 'No sameAs on satellite', sameAsCount === 0, sameAsCount ? sameAsCount + ' sameAs' : 'OK');
}
if (requires_sameas) {
  chk('has_sameas', 'Has sameAs URLs', sameAsCount >= 3, sameAsCount + ' URLs');
}
if (requires_geo) {
  chk('geo_meta', 'Geo meta tags', html.includes('geo.region'), html.includes('geo.region') ? 'OK' : 'Missing');
}

if (role === 'satellite') {
  const hasHub = html.includes('sinabarimd.com');
  chk('hub_link', 'Links to sinabarimd.com', hasHub, hasHub ? 'OK' : 'Missing');
}

const noindex = /name=["']robots["'][^>]*noindex/i.test(html);
chk('not_noindex', 'Not noindexed', !noindex, noindex ? 'NOINDEX!' : 'OK');

const hasArticles = /\/articles\//i.test(html);
chk('articles_link', '/articles/ link', hasArticles, hasArticles ? 'OK' : 'Missing', 'warning');

// Check for broken internal links (articles referenced in homepage)
const internalLinks = [];
const linkRegex = /href=["'](\/articles\/[^"']+\.html)["']/gi;
let linkMatch;
while ((linkMatch = linkRegex.exec(html)) !== null) {
  const path = linkMatch[1];
  if (!internalLinks.includes(path)) internalLinks.push(path);
}

let brokenLinks = [];
for (const path of internalLinks) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'HEAD',
      url: 'https://' + domain + path,
      returnFullResponse: true,
      timeout: 5000,
    });
    if (resp.statusCode >= 400) brokenLinks.push(path);
  } catch(e) {
    brokenLinks.push(path);
  }
}

chk('broken_links', 'No broken internal article links', brokenLinks.length === 0,
  brokenLinks.length === 0 ? internalLinks.length + ' links OK' : 'BROKEN: ' + brokenLinks.join(', '));

const errors = checks.filter(c => c.severity === 'error');
const passedE = errors.filter(c => c.passed).length;
const score = errors.length > 0 ? Math.round((passedE / errors.length) * 100) : 100;
const grade = score >= 95 ? 'A+' : score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 65 ? 'C' : score >= 50 ? 'D' : 'F';

return [{ json: {
  qa_type: 'domain', site_id, domain, checked_at, source: upstream.source,
  score, grade, passed: score >= 80, total_checks: checks.length,
  failed_checks: errors.filter(c => !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  warnings: checks.filter(c => c.severity === 'warning' && !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  checks,
} }];

const result = $json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.domain_results) staticData.domain_results = {};
staticData.domain_results[result.site_id] = {
  domain: result.domain, score: result.score, grade: result.grade,
  passed: result.passed, checked_at: result.checked_at,
  failed_checks: result.failed_checks, warnings: result.warnings,
};
return [{ json: result }];

const sinabarimd_html = $json.sinabarimd_html || '';
const sinabari_net_html = $json.sinabari_net_html || '';
const sbps_html = $json.sbps_html || '';

const checked_at = new Date().toISOString();
const checks = [];
const chk = (id, label, passed, detail, severity = 'error') => {
  checks.push({ id, label, passed, detail, severity });
};

function parseSchemas(html) {
  const types = [];
  let hasAuthorId = false;
  let hasSameAs = false;
  let personCount = 0;
  const ldRegex = /type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/gi;
  let match;
  while ((match = ldRegex.exec(html)) !== null) {
    try {
      const parsed = JSON.parse(match[1]);
      const items = parsed['@graph'] ? parsed['@graph'] : [parsed];
      for (const item of items) {
        if (item['@type']) {
        const t = Array.isArray(item['@type']) ? item['@type'] : [item['@type']];
        types.push(...t);
      }
        const typeArr = Array.isArray(item['@type']) ? item['@type'] : [item['@type']];
        if (typeArr.includes('Person')) personCount++;
        if (item['@id'] === 'https://sinabarimd.com/#sinabari') hasAuthorId = true;
        if (item.author && item.author['@id'] === 'https://sinabarimd.com/#sinabari') hasAuthorId = true;
        if (item.sameAs && Array.isArray(item.sameAs) && item.sameAs.length > 0) hasSameAs = true;
      }
    } catch (_) {}
  }
  return { types, hasAuthorId, hasSameAs, personCount };
}

const sm = parseSchemas(sinabarimd_html);
const sn = parseSchemas(sinabari_net_html);
const sp = parseSchemas(sbps_html);

chk('canonical_person', 'sinabarimd.com has Person schema', sm.types.includes('Person'), 'Found: [' + sm.types.join(', ') + ']');
chk('canonical_profile', 'sinabarimd.com has ProfilePage', sm.types.includes('ProfilePage'), 'Found: [' + sm.types.join(', ') + ']');
chk('sn_no_person', 'sinabari.net has no Person schema', sn.personCount === 0, sn.personCount ? sn.personCount + ' Person found' : 'OK (WebSite)');
chk('sp_no_person', 'sinabariplasticsurgery.com has no Person schema', sp.personCount === 0, sp.personCount ? sp.personCount + ' Person found' : 'OK (WebSite)');
chk('sm_entity', 'sinabarimd.com references /#sinabari', sm.hasAuthorId, sm.hasAuthorId ? 'OK' : 'Missing');
chk('sn_entity', 'sinabari.net references /#sinabari', sn.hasAuthorId, sn.hasAuthorId ? 'OK' : 'Missing');
chk('sp_entity', 'sinabariplasticsurgery.com references /#sinabari', sp.hasAuthorId, sp.hasAuthorId ? 'OK' : 'Missing');
chk('sameas_canonical', 'sameAs only on sinabarimd.com', sm.hasSameAs && !sn.hasSameAs && !sp.hasSameAs,
  (sm.hasSameAs ? 'canonical: yes' : 'canonical: MISSING') + ', ' + (sn.hasSameAs ? 'sinabari.net: HAS' : 'sinabari.net: clean') + ', ' + (sp.hasSameAs ? 'sbps: HAS' : 'sbps: clean'));

const allDistinct = sm.types.sort().join(',') !== sn.types.sort().join(',') && sm.types.sort().join(',') !== sp.types.sort().join(',') && sn.types.sort().join(',') !== sp.types.sort().join(',');
chk('distinct_types', 'Each site has distinct schema @types', allDistinct,
  'sm: [' + sm.types.join(', ') + '] | sn: [' + sn.types.join(', ') + '] | sp: [' + sp.types.join(', ') + ']');

const snHub = sinabari_net_html.includes('sinabarimd.com');
const spHub = sbps_html.includes('sinabarimd.com');
chk('all_link_hub', 'All satellites link to sinabarimd.com', snHub && spHub, 'sinabari.net: ' + (snHub?'OK':'MISSING') + ' | sbps: ' + (spHub?'OK':'MISSING'));

const getTitle = (h) => (h.match(/<title[^>]*>([\s\S]*?)<\/title>/i) || [])[1] || '';
const titles = [getTitle(sinabarimd_html), getTitle(sinabari_net_html), getTitle(sbps_html)].map(t => t.trim());
chk('unique_titles', 'All sites have unique titles', new Set(titles).size === 3, titles.join(' | ').slice(0, 120));

chk('all_load', 'All 3 sites return content', sinabarimd_html.length > 500 && sinabari_net_html.length > 500 && sbps_html.length > 500, 'OK');

const authorRe = /Dr\.?\s*Sina\s+Bari/i;
chk('consistent_author', 'Dr. Sina Bari on all sites', authorRe.test(sinabarimd_html) && authorRe.test(sinabari_net_html) && authorRe.test(sbps_html), 'OK', 'warning');

const errors = checks.filter(c => c.severity === 'error');
const passedE = errors.filter(c => c.passed).length;
const score = errors.length > 0 ? Math.round((passedE / errors.length) * 100) : 100;
const grade = score >= 95 ? 'A+' : score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 65 ? 'C' : score >= 50 ? 'D' : 'F';

return [{ json: {
  qa_type: 'portfolio', checked_at, score, grade, passed: score >= 80,
  total_checks: checks.length,
  failed_checks: errors.filter(c => !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  warnings: checks.filter(c => c.severity === 'warning' && !c.passed).map(c => ({ id: c.id, label: c.label, detail: c.detail })),
  checks,
} }];

const result = $json;
const staticData = $getWorkflowStaticData('global');
staticData.portfolio_result = {
  score: result.score, grade: result.grade, passed: result.passed,
  checked_at: result.checked_at,
  failed_checks: result.failed_checks, warnings: result.warnings, checks: result.checks,
};
return [{ json: result }];

const body = $json.body || $json;
const { qa_type, identifier, check_id, action } = body;
// action: "suppress" or "unsuppress"

if (!check_id) return [{ json: { error: true, message: 'Missing check_id' } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.suppressed_checks) staticData.suppressed_checks = {};

const key = `${qa_type || 'all'}:${identifier || 'all'}:${check_id}`;

if (action === 'unsuppress') {
  delete staticData.suppressed_checks[key];
  return [{ json: { success: true, action: 'unsuppressed', key } }];
}

staticData.suppressed_checks[key] = {
  suppressed_at: new Date().toISOString(),
  qa_type: qa_type || 'all',
  identifier: identifier || 'all',
  check_id,
};

return [{ json: { success: true, action: 'suppressed', key } }];
